local O00OOOOOO='ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/'
local function O000O000O(b)
    b=b:gsub('%s+','')
    b=b:gsub('[^'..O00OOOOOO..'=]','')
    return (b:gsub('.', function(x)
        if x=='=' then return '' end
        local r,f='',(O00OOOOOO:find(x,1,true)-1)
        for i=6,1,-1 do r=r..(f%2^i-f%2^(i-1)>0 and '1' or '0') end
        return r
    end):gsub('%d%d%d?%d?%d?%d?%d?%d?', function(x)
        if #x~=8 then return '' end
        local c=0
        for i=1,8 do if x:sub(i,i)=='1' then c=c+2^(8-i) end end
        return string.char(c)
    end))
end
local O0O0OOO0O=O000O000O(O0O0000OO)
local OO0OO00O0=(bit32 and bit32.bxor) or function(a,b) return a ~ b end
local OOOO00OO0={}
for OOOO0000O=1,#O0O0OOO0O do
    OOOO00OO0[OOOO0000O]=string.char(OO0OO00O0(O0O0OOO0O:byte(OOOO0000O),O000OO00O))
end
OO000OO00(table.concat(OOOO00OO0))()